"""
Standalone patch — writes mkt-context for Isaiah 9-13 directly.
Run: python3 scripts/zc-context-isaiah-9-13-patch.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "9": {
    "1": "<p>Isaiah 9:1 is the pivot verse connecting the darkness of 8:22 ('thick darkness') to the great light. 'There will be no more gloom for her who was in anguish' — the 'her' is the land of Zebulun and Naphtali, the northernmost territories of Israel that Tiglath-Pileser III depopulated in 734-732 BCE (2 Kgs 15:29: 'He took Ijon, Abel Beth Maacah, Janoah, Kedesh and Hazor. He took Gilead and Galilee, including all the land of Naphtali, and deported the people to Assyria'). The territories that were 'humbled first' (qallal = made light of, despised) will be 'honored afterward' (hikbid = made heavy with glory). 'Galilee of the nations' (gelil haggoyim) reflects the mixed ethnic composition of the north. Matthew 4:14-16 cites v1-2 as fulfilled when Jesus began his public ministry in Galilee.</p>",
    "2": "<p>'The people who walked in darkness have seen a great light; those who lived in a land of deep darkness — on them the light has dawned' — the darkness-to-light reversal is one of Isaiah's greatest literary movements, connecting 8:22 ('they will be thrust into thick darkness') to the radiant great light (or gadol) of the messianic era. The verb 'have seen' (ra'u) is prophetic perfect — the future described as already accomplished. 'Deep darkness' (tsalmaveth, shadow of death) is the term used in Ps 23:4 ('the valley of the shadow of death') and Job 10:21-22 for the most extreme darkness. The light dawning on those in the darkest place is the reversal of extremes. John 1:4-9 applies 'the true light' (alethinos phos) language to Jesus.</p>",
    "3": "<p>'You have multiplied the nation; you have increased its joy; they rejoice before you as with joy at the harvest, as warriors celebrate when they divide the plunder' — the two peak celebrations of ancient agricultural/military society: the harvest celebration (the great agricultural festival of Sukkot, Tabernacles, when the harvest was completed and stored) and the warrior's celebration over divided plunder. Both are images of total satisfaction — the labor of months and years rewarded in a moment of abundance. The harvest joy echoes Ps 126:5-6 ('those who sow in tears will reap with songs of joy'). The plunder-dividing joy mirrors Judges 5:30 (Deborah's song: 'Are they not finding and dividing the plunder?').</p>",
    "4": "<p>'For you have broken the yoke of his burden, the staff on his shoulder, the rod of his oppressor, as on the day of Midian' — the three instruments of Assyrian oppression: the yoke (ol, the ox-yoke of subjugation), the staff (matteh, the rod laid across the shoulder of a burden-carrier), and the rod (shevet, the overseer's rod). The 'day of Midian' refers to Gideon's miraculous defeat of the Midianite coalition with 300 men and pitchers (Judg 7) — YHWH's decisive victory with minimal human means, entirely dependent on divine power rather than military strength. The allusion says: the coming messianic deliverance will be as decisively miraculous as Gideon's victory. No human coalition or military strategy is responsible.</p>",
    "5": "<p>'For every boot of the trampling warrior and every garment soaked in blood will be burned as fuel for the fire' — the eschatological end of war itself: the instruments of warfare (the military boot and the blood-soaked campaign garment) are burned as fuel. The 'trampling warrior' (sa'on so'en beraash, the boot that tramples in the noise of battle) is the sound of the military advance — every such boot burned. Ezekiel 39:9-10 develops this into a seven-year burning of Gog's weapons after the final eschatological battle. The burning of military equipment as fuel is the post-war demilitarization: swords-to-plowshares (2:4) taken to its ultimate conclusion — not repurposed but destroyed entirely.</p>",
    "6": "<p>'For to us a child is born, to us a son is given; and the government will rest on his shoulders. His name will be called: Wonderful Counselor, Mighty God, Father of Eternity, Prince of Peace' — the four royal throne-names of the messianic king. In the ancient Near East, the pharaoh was given a long list of throne-names at his coronation; the Isaianic four-name list follows this convention. Pele-yo'ets (Wonderful Counselor): the king's wisdom exceeds human comprehension (pele = miracle/wonder). El-gibbor (Mighty God): the title uses el (God/divine) — the king shares divine identity or is divinely empowered. Abi-ad (Father of Eternity, Everlasting Father): the king's paternal care is eternal. Sar-shalom (Prince of Peace): the king inaugurates the era of shalom. Christian interpretation applies these names to Jesus directly; Jewish interpretation reads them as YHWH's names for his chosen king. Luke 1:32-33 applies v7 to Jesus.</p>",
    "7": "<p>'Of the increase of his government and of peace there will be no end, on the throne of David and over his kingdom, to establish it and uphold it with justice and righteousness from this time forth and forevermore. The zeal of the LORD of hosts will accomplish this' — the eternal Davidic covenant (2 Sam 7:16: 'your throne will be established forever') universalized and eternalized in the messianic king. 'No end' (lo-qets, no cutting off) to the increase (lemarbeh, to the multiplication) of government — the kingdom expands endlessly. 'Justice and righteousness' (mishpat utsedaqah) are the twin pillars of Zion's ideal governance (1:26-27; Ps 89:14). 'The zeal of YHWH of hosts will accomplish this' (qin'at Yhwh tseva'ot ta'aseh zot) — divine passion, not human achievement, produces the messianic outcome. Luke 1:32-33 ('He will reign over Jacob's descendants forever; his kingdom will never end') echoes this directly.</p>",
    "8": "<p>'The Lord has sent a word against Jacob, and it has fallen upon Israel' — the transition from the messianic vision (vv. 1-7) to the judgment-cycle against the Northern Kingdom (vv. 8-21). 'A word against Jacob' (davar baya'aqov) has been sent (shilach, dispatched) like a messenger — the word of YHWH as an active agent that accomplishes its purpose (55:11: 'my word will not return to me empty'). The word has 'fallen upon Israel' (nafal beis-rael) — the judgment oracle lands with the force of a blow. The Northern Kingdom's specific judgment follows in a four-stanza structure, each ending with the refrain of the 'outstretched hand still' (vv. 12, 17, 21; 10:4).</p>",
    "9": "<p>'And all the people will know it — Ephraim and the inhabitants of Samaria — who say in pride and arrogance of heart' — the capital of the Northern Kingdom (Samaria, built by Omri as Israel's new capital, 1 Kgs 16:24) and the tribal designation (Ephraim, the dominant northern tribe). The sin specified: pride and arrogance of heart (begaavah uvegodel levav, in haughtiness and greatness of heart). The pride that refuses to receive the divine word as correction is the fundamental covenant violation — the presumption of self-sufficiency that makes YHWH unnecessary. Deut 8:17: 'You may say to yourself, \"My power and the strength of my hands have produced this wealth for me.\"'</p>",
    "10": "<p>'The bricks have fallen, but we will rebuild with dressed stone; the sycamores have been cut down, but we will plant cedars in their place' — the two-tier bravado of post-judgment reconstruction: replacing fallen bricks with dressed stone (better quality), replacing cut sycamores (a common wood) with cedars (the finest timber). The pride is in the upgrade: not merely restoration but improvement over what was destroyed. Jonathan Cahn's The Harbinger applies this verse to post-9/11 American rebuild confidence, reading it as a type. The theological problem is not reconstruction but the absence of repentance: the response to YHWH's corrective judgment is self-confident rebuilding rather than turning back (v13: 'they have not returned to him who struck them').</p>",
    "11": "<p>'Therefore the LORD raises up the adversaries of Rezin against Israel and stirs up their enemies to attack' — Rezin king of Damascus (Israel's ally in the Syro-Ephraimite coalition of 735-732 BCE) now has YHWH turning his enemies against Israel. The adversaries of Rezin = Assyria (Tiglath-Pileser III who destroyed Damascus in 732 BCE and then turned against Israel). The irony: Israel allied with Damascus against Assyria, and now YHWH uses Assyria through Damascus's defeat to punish Israel. The protective alliance becomes the instrument of exposure.</p>",
    "12": "<p>'The Syrians in front and the Philistines behind, and they devour Israel with open mouth. For all this his anger has not turned away; his hand is stretched out still' — the geographic pincer: Syria (aram, the Arameans) from the northeast and the Philistines from the southwest (the Mediterranean coast). Israel squeezed between two traditional enemies. 'Devour with open mouth' (yochelu Yisrael befeh-male, they eat Israel with full mouth) — the consumption metaphor for military conquest and economic exploitation. The refrain 'his anger has not turned away, his hand is stretched out still' (lo-shav apo ve'od yado netuyah) concludes the first stanza and will repeat three more times (9:17, 9:21, 10:4).</p>",
    "13": "<p>'But the people have not returned to him who struck them, nor have they sought the LORD of hosts' — the fundamental diagnosis: the corrective judgment has failed to produce repentance. 'Have not returned' (velo-shavu, and they did not turn/return) — the shuv (return/repentance) vocabulary of the prophets: YHWH strikes to produce shuv, Israel refuses to shuv. 'Have not sought' (velo-biqqeshu, and they did not seek) the LORD of hosts — the lack of consultation of YHWH in crisis (as contrasted with seeking mediums in 8:19). The refusal to seek YHWH produces the escalating judgment cycle: YHWH strikes, they rebuild confidently (v10), they don't return (v13), judgment intensifies.</p>",
    "14": "<p>'So the LORD cut off from Israel head and tail, palm branch and reed, in a single day' — the comprehensive social removal: head (rosh) and tail (zanav) + palm branch (kippah, the palm top/honorable) and reed (agmon, the bulrush/worthless low). Two sets of two describe the entire social spectrum: from the most honored (head/palm-top) to the most worthless (tail/bulrush). 'In a single day' (yom echad) — the sudden, comprehensive nature of the divine judgment. The specific identification follows in v15: the honored elder is the head, the lying prophet is the tail.</p>",
    "15": "<p>'The elder and honored man is the head, and the prophet who teaches lies is the tail' — the identification of the social categories: zaqen (elder) and nesi-panim (one of elevated face/status) = the honorable social establishment (the head); navi-moreh-shaqer (the prophet who teaches falsehood) = the tail. The false prophet is not at the bottom of society but at its religious apex — yet is identified as the least significant element. This anticipates the sustained anti-false-prophet polemic of Jeremiah (chs. 23; 27-29) and Ezekiel (chs. 12-14). The false prophet who should be guiding the nation toward repentance is instead teaching lies that reinforce false confidence.</p>",
    "16": "<p>'For the guides of this people have led them astray, and those whom they lead are swallowed up' — the pastoral metaphor of misleading: the guides (meavsherav, those who lead this people, literally 'those who make happy/cause to prosper') have led them astray (vita'um, caused them to go astray — the same root as the lost sheep metaphor). Both the leaders (who misguide) and the led (who are misguided) face the same fate: the led are 'swallowed up' (mevuleaim, consumed). The leaders' culpability is greater because they knew YHWH's requirements and misrepresented them. Luke 6:39: 'Can the blind lead the blind? Will they not both fall into a pit?'</p>",
    "17": "<p>'Therefore the Lord does not rejoice over their young men, and has no compassion on their fatherless and widows, for everyone is godless and an evildoer, and every mouth speaks folly. For all this his anger has not turned away; his hand is stretched out still' — the most shocking element of the second stanza: YHWH has no compassion on the fatherless and widows. These were the paradigmatic recipients of covenant mercy (1:17; Deut 10:18; 27:19). When the entire society has become godless (chanef, profaned/polluted) and wickedness is universal ('every mouth speaks folly'), even the categories normally protected by divine compassion are swept up in the judgment. The refrain closes the second stanza.</p>",
    "18": "<p>'For wickedness burns like a fire; it devours briers and thorns; it kindles the dense forest thickets, and they roll up in columns of smoke' — the self-consuming nature of social wickedness: the metaphor of a wildfire that spreads from underbrush (briers and thorns, shamir vashayit — the judgment-vegetation of 5:6 and 7:23-25) into the dense forest, producing smoke columns. Wickedness is not merely a crime against YHWH but a self-destructive social force: the community's own sins become the fuel for its destruction. The fire metaphor continues in v19: YHWH's wrath as the scorching agent, and in v20-21: the people devouring each other like famine-driven cannibals.</p>",
    "19": "<p>'Through the wrath of the LORD of hosts the land is scorched, and the people are like fuel for the fire; no one spares his brother' — the combination: YHWH's wrath provides the heat, the people's wickedness provides the fuel. The social disintegration: 'no one spares his brother' (ish et-achiv lo yachmolu, each man does not spare/pity his brother) — the family covenant broken. In famine and siege conditions, the breakdown of the social bond of family solidarity was the ultimate index of societal collapse. Lam 4:10 describes the ultimate collapse: mothers boiling their own children during the Jerusalem siege.</p>",
    "20": "<p>'They snatch food on the right but are still hungry; they eat on the left but are not satisfied; each one devours the flesh of his own kinsman' — the insatiable hunger (right-hand/left-hand = everywhere, exhausting all possibilities) without satisfaction. 'Devours the flesh of his own kinsman' (zeroa achiv ye'ochehu) — a vivid image of the social cannibalism produced by societal breakdown: people exploiting, consuming, and destroying their own family members for survival. This may be both literal (siege conditions) and metaphorical (economic exploitation of kin). Zechariah 11:9 uses the same imagery: 'Let the dying die... let the rest devour each other's flesh.'</p>",
    "21": "<p>'Manasseh devours Ephraim, and Ephraim devours Manasseh, and both together are against Judah. For all this his anger has not turned away; his hand is stretched out still' — the tribal cannibalism: Manasseh and Ephraim were brother tribes (sons of Joseph, Gen 41:51-52), occupying adjacent northern territories. Their mutual devouring (one eating the other) represents civil war and fratricidal violence within the covenant community. Both then unite against Judah — the Syro-Ephraimite coalition (7:1-6) being an instance of the north attacking the south. The refrain closes the third stanza, leaving the fourth stanza (10:1-4) to complete the cycle.</p>"
  },
  "10": {
    "1": "<p>Isaiah 10:1-4 is the seventh woe-oracle (connecting to the six of ch. 5 with the same refrain in v4). 'Woe to those who enact unjust laws and to those who issue oppressive rulings' — the specific sin is legislative injustice: creating laws (hoqeq, those who carve/inscribe laws) that are aven (wickedness/worthlessness) and issuing decrees (metaqqenim, those who write/inscribe rulings) that are amal (toil/oppression). The attack on the legal system rather than merely its practitioners is striking: the problem is not only corrupt judges but laws designed from the start to produce unjust outcomes. Amos 6:12 and Micah 3:9-11 make the same charge against the judicial establishment.</p>",
    "2": "<p>'Turning the poor away from justice and robbing the rights of the afflicted of my people, making widows their spoil and orphans their prey' — the specific victims: the poor (dallim, the thin/lowly ones), the afflicted of my people (aniyyei ammi, the poor/afflicted of YHWH's people), widows (almanot), and orphans (yetomim). The four-fold vulnerable list is the comprehensive covenant-protection category (Exod 22:21-27; Deut 24:17-22). The oppressive officials 'make widows their spoil' (lihyot almanot shallam, to be widows as their spoil) and 'orphans their prey' (yetomim yavozzeu, they plunder orphans) — the most powerful preying on the most helpless as their economic opportunity.</p>",
    "3": "<p>'What will you do on the day of reckoning, when devastation sweeps in from afar? To whom will you run for help? Where will you store away your wealth?' — the day of reckoning (yom pequdah, the day of visitation/accounting — the Day of the LORD applied specifically to these unjust rulers). The three questions expose the futility of the wealth accumulated through oppression: when devastation comes from afar (Assyria), neither the wealth nor the official position provides protection. 'Where will you store away your wealth?' (efo taazovu kevodam, where will you leave your glory?) — the stored glory/wealth becomes a burden rather than a protection when YHWH's judgment arrives.</p>",
    "4": "<p>'There is nothing left but to cower among captives or collapse among the dead. For all this his anger has not turned away, and his hand is stretched out still' — the final refrain completing the four-stanza cycle that began at 9:8. The alternatives for the oppressive rulers on the day of judgment: crouching (kara') under the captives as a captive themselves, or falling (naphal) among the slain. Neither option preserves dignity or wealth. The refrain 'his anger has not turned away, his hand is stretched out still' (lo-shav apo ve'od yado netuyah) appears for the fourth and final time, closing the judgment cycle. The relentless divine hand that has been raised through four stanzas has now accomplished its work — ch. 10:5ff turns to the Assyrian instrument itself.</p>",
    "5": "<p>'Woe, Assyria — you are the rod of my anger; the club in whose hand is my fury!' — the Assyrian paradox: the oracle against Assyria begins with a woe (hoy Ashshur, woe Assyria), but the content establishes Assyria as YHWH's instrument. The 'rod of my anger' (matteh appо, rod of my nostril-anger) and 'club in whose hand is my fury' (vehu veyado za'ami, and he is the club in whose hand is my fury). The rod/club are the instruments of punishment used by masters, judges, and conquerors. Assyria as YHWH's rod means YHWH is directing the punishment even though Assyria does not know it (v7). This is the sovereignty-over-evil paradox: YHWH using the wicked as instruments without making them righteous or absolved of culpability.</p>",
    "6": "<p>'I am sending him against a godless nation; I am ordering him against the people of my wrath to take spoil and seize plunder and to trample them like mud in the streets' — YHWH's explicit commission of Assyria: 'I am sending' (ashalechenu, I send him) and 'I am ordering' (atsavenu, I command him) against a 'godless nation' (goi chanef, a polluted/profaned nation = Israel/Judah). The purposes: to take spoil (laslol shalal), seize plunder (velaboz baz), and trample (lesumah meevus) like street mud. The trampling imagery is the Assyrian war-machine's standard treatment of conquered populations — the prophetic literature regularly uses muddy street imagery for military defeat (Mic 7:10; Zech 10:5).</p>",
    "7": "<p>'But that is not his intention, and that is not what his heart plans; for his heart is fixed on destruction, on wiping out many nations' — the theological paradox: Assyria serves YHWH's purpose without intending to. The Assyrian king's actual intention (lo-ken yidmeh, not thus does he suppose) is self-aggrandizement and empire-building, not covenantal discipline. 'His heart is fixed on destruction' (lebavo lhashmed, his heart is to cut off) — the king's own agenda is genocidal conquest, not remedial punishment. YHWH uses Assyria's ambition of conquest as the instrument of his disciplinary judgment, while Assyria believes it acts from its own power. The philosophical problem: how can a free moral agent (Assyria) be simultaneously YHWH's instrument and culpably proud? Isaiah's answer is that YHWH limits the scope (v12: after the work on Zion is done) without removing the agent's moral responsibility.</p>",
    "8": "<p>'For he boasts: Are not all my officers kings?' — the Assyrian king's boasting (ki yomar, for he says). 'All my officers are kings!' (hayyelo saray melechim, are not all my princes kings?) — the Assyrian administrative system in which provincial governors held rank equivalent to client-kings, suggesting the empire's vast extent and the king's surpassing greatness. The boasting formula introduces the catalogue of conquered cities (vv. 9-11) as evidence for the king's claim. The Assyrian annals are filled with exactly this kind of city-list boasting — they document the empire's victories as proof of divine favor and royal power.</p>",
    "9": "<p>'Was not Calno taken as easily as Carchemish? Was not Hamath treated like Arpad? Was not Samaria like Damascus?' — the three paired conquests documenting Assyrian advance: Calno/Carchemish (both in northern Syria, taken by Tiglath-Pileser III in 738 and 717 BCE); Hamath/Arpad (Hamath in central Syria fell to Sargon II; Arpad fell to Tiglath-Pileser); Samaria/Damascus (Samaria fell to Sargon II in 722 BCE after a 3-year siege; Damascus fell to Tiglath-Pileser in 732 BCE). The rhetorical point: each new conquest was 'as easy as' the previous one — the pattern of effortless victory leads the king to assume Jerusalem will be the same.</p>",
    "10": "<p>'Just as my hand reached kingdoms whose idols surpassed those of Jerusalem and Samaria' — the Assyrian king's theological argument: the kingdoms he conquered had more impressive idols than Jerusalem, yet they fell. The argument implies that Jerusalem's deity (YHWH) is no more effective than the defeated deities. This is the Rabshakeh's argument in 2 Kgs 18:33-35 and Isa 36:18-20: 'Has the god of any nation ever delivered his land from the hand of the king of Assyria? Where are the gods of Hamath and Arpad?' The king treats YHWH as one national deity among many, all equally powerless before Assyrian military power.</p>",
    "11": "<p>'Shall I not treat Jerusalem and her idols just as I treated Samaria and her carved images?' — the rhetorical climax of the Assyrian boast: Jerusalem will fall like Samaria. The king explicitly equates YHWH with the idols (gillulim, dung-idols — Isaiah's contemptuous term) of Samaria. The theological category error: treating YHWH as a national tutelary deity of the same type as Samaria's calves (1 Kgs 12:28-29) rather than as the creator and sovereign of all nations. The king does not know (as YHWH's word through Isaiah repeatedly insists) that YHWH is the one who sent Assyria and will recall it when the work is done.</p>",
    "12": "<p>'Once the Lord has completed his work on Mount Zion and in Jerusalem, he will deal with the arrogant boasting of the heart of the king of Assyria and the proud look in his eyes' — the scope limitation on divine use of Assyria: 'when he has finished' (ki-yivale Adonay, when the Lord has finished) his work (ma'asah) on Zion. After the disciplinary purpose is accomplished, YHWH turns against the instrument. The boasting heart (peri-godel levav, fruit of the greatness of the heart = the product of Assyria's arrogance) and the haughty eyes (tiferet romut einav, glory of his haughty eyes) become the objects of divine punishment. YHWH punishes both the pride of Israel and the pride of his instrument.</p>",
    "13": "<p>'It is by my own power and wisdom that I have done this, for I am shrewd. I have erased the borders of nations and plundered their accumulated wealth; like a conquering champion I have toppled their enthroned rulers' — the Assyrian king's self-congratulation in v13-14 is the most extensive royal self-praise in the prophetic literature. 'By my own power and wisdom' (bekochi vebekhochmati, in my strength and in my wisdom) — precisely the arrogance Deut 8:17 warns against ('my own power and the strength of my hands have produced this wealth for me'). The three specific achievements claimed: erasing national boundaries, plundering accumulated wealth, and toppling enthroned rulers. Each represents a specific aspect of Assyrian imperial technique (redrawing provincial boundaries, extraction of tribute, exile of local kings).</p>",
    "14": "<p>'I have scooped up the riches of the peoples as easily as collecting eggs from a deserted nest; there was no wing stirred, no beak opened, no chirp of protest' — the egg-collecting simile for effortless conquest: the conqueror reaches into an unguarded nest and takes the eggs with no resistance from the parent birds. The three negatives (no wing, no beak, no chirp) describe total absence of resistance. This is the ultimate expression of invincibility — even the instinctual parental defense of birds has been absent. The simile's effect is to display the king's total confidence and contempt for opposition, which is precisely what YHWH now punishes in vv. 15-19.</p>",
    "15": "<p>'Does an axe boast over the person who wields it? Does a saw exalt itself above the hand that drives it? As if a club could brandish the man who holds it, or a staff lift up a person who is not made of wood!' — the tool-and-craftsman analogy that exposes the Assyrian king's theological error. The axe (garzen), saw (massor), club (shevet), and staff (maqqel) are four tools that cannot act independently of the one who wields them. YHWH is the craftsman; Assyria is the tool. The tool that claims autonomous agency ('by my own power and wisdom,' v13) reverses the proper order. Augustine (City of God 5.21) uses this image to discuss how YHWH uses evil powers as instruments. Paul's 'clay and potter' argument in Rom 9:20-21 is in the same tradition.</p>",
    "16": "<p>'Therefore the Sovereign LORD of hosts will send a wasting disease among the Assyrian's stout warriors; beneath his glory a blaze will be kindled like a consuming fire' — the punishment matching the pride: the 'stout warriors' (mishmanav, his fat ones — the well-fed elite troops) will be reduced by 'wasting disease' (razzon, leanness/wasting). The fire 'beneath his glory' (tachat kevodo, under his glory/weight) is the divine fire that burns from within. The immediate historical fulfillment: the angel of YHWH striking 185,000 Assyrian troops in the night during Sennacherib's siege of Jerusalem in 701 BCE (2 Kgs 19:35; Isa 37:36) — one of the most remarkable events in biblical history.</p>",
    "17": "<p>'The Light of Israel will become a fire, and his Holy One a flame; it will blaze up and devour his thorns and his briars in a single day' — 'the Light of Israel' (or Yisrael, the light of Israel) as the divine identity: YHWH is Israel's light (Ps 27:1: 'The LORD is my light and my salvation') who becomes consuming fire when turned against the arrogant. The thorns and briars of the Assyrian forest are the same shamir vashayit that represents divine judgment on Israel throughout Isaiah (5:6; 7:23-25; 9:18) — now applied to Assyria itself. 'In a single day' (beyom echad, in one day) echoes the 'single day' of the social catastrophe in 10:14 — YHWH's judgment is sudden and complete.</p>",
    "18": "<p>'It will consume the glory of his forest and his fertile fields, root and branch; and he will fade and waste away like a dying man' — the Assyrian empire as a great forest (forest = military/imperial power) consumed: from the great trees to the undergrowth (root and branch — mibbi nefesh ve'ad basar, from being to flesh = from soul to flesh = utterly), until Assyria 'fades and wastes away like a dying man' (kivnos noseis me'al, as a standard-bearer wastes away). The 'fading' metaphor: Assyria's power wasting away like a sick person reduced to a skeleton by fever. The pride of military conquest (v13-14) ends in fading disease (v16, 18).</p>",
    "19": "<p>'The trees left standing in his forest will be so few that even a child could count them and write them down' — the reversal of Assyrian power reduced to countable remnants. The Assyrian empire that marched with uncountable armies (5:27-29: not one tired, not one sleeping) will be reduced to a remnant 'a child could write down' — the counting and writing are marks of smallness (too few for an adult specialist to track). The image plays against the massive Assyrian king-lists and conquest records that enumerate their victories; now Assyria's survivors are reduced to what a child could note. 2 Kgs 19:36-37 records Sennacherib's withdrawal to Nineveh after the angel's destruction of his army.</p>",
    "20": "<p>'In that day the remnant of Israel and the survivors of Jacob's house will no longer rely on the one who struck them, but will truly lean on the LORD, the Holy One of Israel' — the remnant theology applied after the Assyrian catastrophe: those who survive will have learned the lesson Ahaz refused (7:9: 'if you do not stand firm in faith, you will not stand at all'). 'No longer rely on the one who struck them' (lo-yosif od lehishaen al-makkehv) = no longer seeking Assyrian alliance as Ahaz did (2 Kgs 16:7-8). 'Truly lean on YHWH' (nishaan al-Yhwh) — the leaning/resting posture of faith contrasted with the anxious political calculation. Hezekiah's response to the Assyrian siege (2 Kgs 19:1-19) models this remnant faith.</p>",
    "21": "<p>'A remnant will return, the remnant of Jacob, to the mighty God' — she'ar yashub, she'ar ya'aqov el-El-gibbor (a remnant will return, the remnant of Jacob, to the Mighty God). This is the name of Isaiah's son Shear-jashub (7:3) unpacked: the son's very name proclaimed this truth. The title 'Mighty God' (El-gibbor) is the same divine name applied to the Davidic child in 9:6 — the returning remnant comes back to the messianic deity. The full circle: the divine name of the messianic King (9:6) is now the destination of the returning remnant (10:21). God is both the Davidic King and the one the remnant returns to.</p>",
    "22": "<p>'For though your people, Israel, are as numerous as the sand of the sea, only a remnant will return. Destruction has been decreed; it brims over with righteousness' — Paul cites this verse (Rom 9:27-28) in his argument that God's election of Israel does not require the salvation of all ethnic Israelites: 'Though the number of the Israelites be like the sand by the sea, only the remnant will be saved.' The sand-of-the-sea promise was the Abrahamic blessing (Gen 22:17: 'your descendants like the sand of the seashore'), now turned against the expectation of universal Israelite salvation. 'Destruction decreed, brims over with righteousness' (kalah venechratsah tsedaqah shotef, a destruction and a decreed thing brims over in righteousness) — the decree of destruction itself is an act of divine righteousness/justice.</p>",
    "23": "<p>'For the Lord GOD of hosts is executing his decreed destruction throughout the whole land' — the comprehensive scope of the ordained judgment: the Lord GOD of hosts (Adonay Yhwh tseva'ot) is making a 'decreed destruction' (kalah venechratsah, a complete and determined thing) in the whole earth/land (beqerev kol-ha'arets). The 'decreed' language (charuts, determined/decided — the same root as Nebuchadnezzar's dream interpretation in Dan 9:26: 'until the end that is decreed') indicates irreversible divine decision. But the remnant survives this comprehensive destruction, as the previous verses have emphasized.</p>",
    "24": "<p>'Therefore this is what the Lord GOD of hosts says: O my people who live in Zion, do not be afraid of Assyria, even when he strikes you with his rod and raises his staff against you as Egypt once did' — the pastoral application: after the theological explanation (Assyria is YHWH's instrument), the people of Jerusalem are commanded not to fear. The rod-and-staff imagery of 9:4 (the rod of Israel's oppressor broken 'as on the day of Midian') now applied to Assyria: they will strike with a rod and raise a staff 'as Egypt once did.' The Egypt comparison promises a new Exodus: YHWH who delivered from Egypt will deliver from Assyria through the same pattern of divine intervention.</p>",
    "25": "<p>'For in a very little while my fury will be spent, and my anger will turn against their destruction' — the time limitation: 'in a very little while' (ki od me'at miz'ar, for in yet a little, a very little while) YHWH's anger will be spent on Israel and will then turn (hapakh, turn around) against Assyria's destruction. The turning of divine anger from Israel to Assyria is the theological sequence: first the instrument of discipline, then the disciplining of the instrument. The '701 BCE deliverance' from Sennacherib's army is the specific historical event anticipated — after years of Assyrian domination, YHWH suddenly turned against the invader.</p>",
    "26": "<p>'The LORD of hosts will lash out against them as he defeated Midian at the rock of Oreb; and he will raise his staff over the sea as he raised it against Egypt' — the two great military miracles invoked: Gideon's defeat of Midian at the rock of Oreb (Judg 7:25: Oreb the Midianite commander killed at the rock named for him) and Moses raising his staff over the Red Sea (Exod 14:16-28). The two paradigmatic YHWH-warrior victories without human military power promise that YHWH will defeat Assyria by the same miraculous means. The staff over the sea (v26) = the exodus-staff imagery, anticipating 11:15-16's second-exodus through the dried sea.</p>",
    "27": "<p>'In that day his load will be lifted from your shoulder and his yoke from your neck; the yoke will be shattered because of the anointing' — the liberation from Assyrian oppression uses the yoke/load imagery of 9:4 (the yoke and rod of oppression broken 'as on the day of Midian'). 'The yoke will be shattered because of the anointing' (vachulal ol mipene-shamen, the yoke will be destroyed from before the fat/anointing) is textually difficult: shamen can mean fatness (the ox growing too fat for the yoke) or anointing oil (the royal anointing of the Davidic king, or the Servant/Messiah). The messianic reading connects to 9:6-7 (the child whose government will be without end) and 11:1-5 (the Spirit-anointed Branch who breaks oppression).</p>",
    "28": "<p>'He advances to Aiath, passes through Migron, and stores his equipment at Michmash' — the detailed march route of Sennacherib's army through the northern approaches to Jerusalem. The villages named (Aiath/Ai, Migron, Michmash, Geba, Ramah, Gibeah, Nob — all within 10-15 miles north and northeast of Jerusalem) trace the Assyrian advance down the main north road. The precision of the topographic description reflects either contemporary knowledge of Sennacherib's 701 BCE campaign route or an earlier Assyrian march. Michmash was Jonathan's site of victory (1 Sam 14:5-6): a location with associative memories of miraculous YHWH-victory.</p>",
    "29": "<p>'They cross the mountain pass; at Geba they camp for the night; Ramah shakes with fear; Gibeah of Saul has abandoned its position' — the psychological terror propagating ahead of the army: Ramah 'shakes' (charadah, trembles) and Gibeah of Saul (the original capital of Saul's kingdom, 1 Sam 11:4; 13:2-3) 'has abandoned its position' (nedad, fled/is in flight). The advance of terror precedes the army itself — the mere knowledge of the Assyrian approach empties cities. This is the Deuteronomic covenant curse of Lev 26:36 ('the sound of a wind-blown leaf will put them to flight') made geographically specific.</p>",
    "30": "<p>'Cry out loudly, O daughter of Gallim! Listen, O Laishah! O Anathoth, answer her!' — Anathoth is significant: the priestly town just north of Jerusalem that was the birthplace of Jeremiah (Jer 1:1). The cry (tsahali qoli, lift up your voice) addressed to these northern Jerusalem suburbs creates a soundscape of panic spreading from village to village. The 'daughter of Gallim' (bat-Gallim) uses the feminine-city personification familiar from 'daughter of Zion' — each village personified as a terrified woman calling out to neighbors.</p>",
    "31": "<p>'Madmenah has fled; the people of Gebim are running for cover' — continued flight narrative: two more villages north of Jerusalem emptied before the advancing Assyrian force. The names' Hebrew meanings may carry irony: Madmenah (dunghill) flees, Gebim (cisterns) runs for shelter. The northward villages' progressive evacuation creates a dramatic forward-movement of terror toward Jerusalem, climaxing in v32 when the army halts at Nob and shakes its fist at Jerusalem.</p>",
    "32": "<p>'That same day he will halt at Nob and shake his fist toward the hill of Zion, the mount of Jerusalem' — Nob (the 'city of priests,' 1 Sam 21:1-9; 22:19) was on the Mount of Olives with a direct line of sight to Jerusalem (modern Ras Umm at-Talaa). The Assyrian king 'shaking his fist' (yenofef yado, waves his hand) at Mount Zion from Nob is the gesture of menacing threat — the same gesture YHWH raises against enemies (11:15; 19:16). The visual image of the Assyrian king on the opposite ridge gesturing at Jerusalem's temple mount is the poem's dramatic climax.</p>",
    "33": "<p>'But see — the Sovereign LORD of hosts is about to lop off the branches with terrifying force; the towering will be cut down and the lofty brought low' — the divine reversal: at the moment of maximum Assyrian menace (v32), YHWH the forester begins hacking down the great trees. 'Lop off the branches' (meot-pe'urah, cutting/hacking the boughs) with a 'crash' (bema'arutsah, with terrifying force) — the same 'towering' (ramah) and 'lofty' (nesu) that the Day of the LORD brought low in 2:13-14 (the cedars and oaks) are now applied to the Assyrian great ones.</p>",
    "34": "<p>'He will slash down the dense forest with iron, and Lebanon will fall before a powerful one' — Lebanon's great forests were the symbol of imperial power and timber wealth throughout the ANE. 'With iron' (babarzel, by the iron axe) — the divine lumberjack using the iron axe to fell the Assyrian forest. 'Lebanon will fall before a powerful one' (vehaLevanon beadir yippol) — the powerful one (adir, the majestic/mighty one) who fells Lebanon is YHWH himself. The same image appears in Ezek 31:3-18 where Egypt is compared to a great cedar of Lebanon that YHWH cut down. The forest image cuts perfectly into the Branch-from-Jesse that begins ch. 11: Assyria's great trees fall, and from the humble stump of Jesse a shoot grows.</p>"
  },
  "11": {
    "1": "<p>'A shoot will come up from the stump of Jesse, and a branch from his roots will bear fruit' — the perfect continuity with 10:33-34: Assyria's great forest is felled, but from the stump of Jesse (David's father) a shoot (choter, a young twig/sapling) grows. Jesse rather than David as the root deliberately goes back before the Davidic monarchy — the new king comes not from the corrupt royal succession but from the original stock. The 'branch' (netser, shoot/sprout) has a possible connection to the town name Nazareth (natsrath, from netser): Matthew 2:23 cites 'He will be called a Nazarene' as fulfillment of prophecy, possibly alluding to this 'branch' text. 'Bear fruit' (yifre, will bear fruit) from roots that seemed dead — the stump theology of 6:13 made productive.</p>",
    "2": "<p>'The Spirit of the LORD will rest on him — the Spirit of wisdom and understanding, the Spirit of counsel and strength, the Spirit of knowledge and the fear of the LORD' — the seven-fold Spirit: (1) the Spirit of YHWH (the comprehensive designation), then six in pairs: (2) wisdom (hochmah) + (3) understanding (binah), (4) counsel (etsah) + (5) strength (gevurah), (6) knowledge (da'at) + (7) fear of YHWH (yir'at Yhwh). The number seven (completeness) and the three pairs (wisdom-practical, counsel-executive, knowledge-devotional) describe the complete endowment of the ideal king. Revelation 1:4; 3:1; 4:5; 5:6 applies the seven-fold Spirit to the divine presence before God's throne. John 1:32-33 records the Spirit resting (meno, abiding) on Jesus at his baptism — the 'rest' (nuach) verb of Isaiah 11:2.</p>",
    "3": "<p>'He will take delight in the fear of the LORD. He will not judge by what his eyes see or decide cases by what his ears hear' — the messianic king's epistemology: judgment by inner discernment (divine wisdom) rather than outward appearance (eyes and ears). The delight in the fear of YHWH (vaharicho beyir'at Yhwh, and his delight/breath will be in the fear of YHWH) is the character of the sage who operates from covenant wisdom rather than political calculation. The contrast with human judges who can be bribed (appearance-based judgment) or deceived (hearing false testimony) marks the Davidic ideal never achieved by any historical king.</p>",
    "4": "<p>'But with righteousness he will judge the poor and with fairness he will decide for the humble of the earth; he will strike the earth with the rod of his mouth, and with the breath of his lips he will put the wicked to death' — the specific beneficiaries of messianic judgment: the poor (dallim) and humble (anavei erets). The instruments of his power: 'the rod of his mouth' (shevet pihu, the rod/staff of his mouth = his word as a weapon) and 'the breath of his lips' (ruach sefatav, the spirit/breath of his lips). Revelation 19:15 directly applies these images to the returning Christ: 'Out of his mouth comes a sharp sword with which to strike down the nations.' 2 Thess 2:8 applies the 'breath of his mouth' to the destruction of the lawless one at Christ's coming.</p>",
    "5": "<p>'Righteousness will be the belt around his waist, and faithfulness the girdle around his hips' — the royal investiture garments made moral: the belt (ezor, the sash worn around the waist for dignity and identification of status) is tzedaqah (righteousness) and the girdle around the loins is emunah (faithfulness/trustworthiness). Eph 6:14 applies this to the armor of God: 'Stand firm then, with the belt of truth buckled around your waist, with the breastplate of righteousness in place.' The contrast with the Zion-women's ornamental belt-and-sash (3:20-24, stripped as judgment) is striking: what the unfaithful women wore as adornment, the messianic king wears as his very character.</p>",
    "6": "<p>'The wolf will live peacefully with the lamb, and the leopard will lie down with the young goat; the calf and the young lion and the fatling will be together, and a little child will lead them' — the peaceable kingdom: predator-prey reversal as the eschatological sign of new creation. Wolf (ze'ev) with lamb (keves), leopard (namer) with young goat (gedi), calf (egel) with young lion (kefir) — three natural predator-prey pairs now cohabiting. 'A little child will lead them' (yeled qatan noheg bam, a little child leads them) — the most vulnerable human being (a small child who cannot defend itself) safely directs the formerly dangerous animals. The child echoes the 'child born to us' of 9:6, suggesting the messianic presence enables the peaceable kingdom.</p>",
    "7": "<p>'The cow and the bear will graze together; their calves will lie down side by side; and the lion will eat straw like the ox' — the dietary transformation: the bear (dov) grazing with the cow (parah), their young ones together, and the lion eating straw (teven, the leftover dry stalks after threshing). The lion eating straw is the most astonishing reversal — the apex predator converted to a herbivore. Genesis 1:29-30 records the original diet as plants for all living things; only after the flood (Gen 9:3) does YHWH permit meat-eating. The peaceable kingdom is thus a restoration of pre-fall Eden rather than a new invention — creation returned to its original design.</p>",
    "8": "<p>'The nursing infant will play at the viper's burrow, and the toddler will reach his hand into the adder's den' — the snake imagery completes the Eden-reversal: the most primal human fear (the serpent of Gen 3) is defanged in the messianic kingdom. 'Nursing infant' (yoneq, the suckling) playing at the viper's (pethen) hole and the 'toddler' (gamul, the newly weaned child) reaching into the adder's (ef'eh) den. Both venomous snakes — the pethen is the cobra of Egypt, the ef'eh is the desert viper. The child who formerly could not survive snake contact now plays at their dens without harm. The curse of Gen 3:15 ('it will strike your heel') is reversed.</p>",
    "9": "<p>'Nothing will harm or destroy anywhere on my holy mountain, for the earth will be filled with the knowledge of the LORD as completely as the waters cover the sea' — the 'why' behind the peaceable kingdom: the universal knowledge of YHWH (da'at Yhwh) is the foundation. The same 'da'at' that was the cause of Israel's judgment ('destroyed from lack of knowledge,' Hos 4:6) now fills the earth as completely as water covers the sea — an image of total, pervasive saturation. The comparison 'as the waters cover the sea bed' (kamayim layam mechasim) describes the impossibility of the land being uncovered: the sea bottom is never exposed. Habakkuk 2:14 uses the same phrase: 'the earth will be filled with the knowledge of the glory of the LORD as the waters cover the sea.'</p>",
    "10": "<p>'In that day the Root of Jesse will stand as a banner for the peoples; the nations will seek him, and his resting place will be filled with glory' — the second major designation: the 'Root of Jesse' (shoresh Yishai, the root/stock of Jesse) rather than the 'shoot from Jesse's stump' (v1). The Root is the source from which the stump grows — the king is not only the descendant of Jesse but his root, his origin. Paul cites this verse in Rom 15:12 as the scriptural promise of Gentile inclusion: 'the Root of Jesse will spring up, one who will arise to rule over the nations; in him the Gentiles will hope' (citing the LXX which has 'rule' and 'hope in him'). The banner/signal (nes, standard raised to summon troops or nations) standing for the peoples (le'ammim) draws them to YHWH's dwelling place.</p>",
    "11": "<p>'In that day the Lord will extend his hand a second time to reclaim the remnant of his people who are left — from Assyria, from Egypt, from Pathros, from Cush, from Elam, from Shinar, from Hamath, and from the islands of the sea' — the second Exodus: YHWH extending his hand 'a second time' (shenit, a second time) to reclaim (liqnot, to acquire/redeem) the remnant (she'ar, the residue/remnant) of his people scattered across all the known world. Eight geographical regions are listed: east (Assyria, Elam, Shinar/Babylon), south (Egypt, Pathros/Upper Egypt, Cush/Ethiopia), north (Hamath), and west ('islands of the sea' = Mediterranean coast and islands). The comprehensive geographic list covers every direction of dispersion.</p>",
    "12": "<p>'He will raise a banner for the nations and gather the exiled of Israel; he will assemble the scattered of Judah from the four corners of the earth' — the eschatological ingathering: the banner (nes) of v10 is raised for the nations to signal the gathering of Israel's exiles. Both the northern kingdom ('exiled of Israel,' nidchei Yisrael) and the southern ('scattered of Judah,' nefutsot Yehudah) are gathered. 'From the four corners of the earth' (mearba kanfot ha'arets, from the four wings/corners of the earth) — the comprehensive directional gathering, anticipating the ingathering of the Jewish diaspora from all directions. Ezek 37:21-22 (the valley of dry bones) and Zech 10:8-10 develop the same second-Exodus theology.</p>",
    "13": "<p>'Ephraim's jealousy will come to an end, and those who antagonise Judah will be cut off; Ephraim will not envy Judah, and Judah will not vex Ephraim' — the healing of the north-south division: the rival jealousy (qin'at Efraim, the jealousy of Ephraim) and the antagonism of Judah (tsorerai Yehudah) — the north-south tension that erupted in the kingdom division of 931 BCE and persisted through the Syro-Ephraimite conflict (7:1-9; 9:8-21) — will be resolved in the messianic age. The two halves of the covenant people unified. Ezek 37:15-23 (the two sticks becoming one in Ezekiel's hand) develops this same north-south reunification promise.</p>",
    "14": "<p>'Together they will swoop down on the Philistines to the west and jointly plunder the peoples of the east; they will reach out against Edom and Moab, and the Ammonites will submit to them' — the reunited Israel's military power directed outward: the traditional enemies (Philistines to the west, Edom/Moab/Ammon to the east and southeast) now subdued. The reunion of north and south produces military strength that neither had separately. This is the fulfillment of the Davidic ideal of a united kingdom dominating the surrounding nations — a reality briefly achieved under David and Solomon but lost at the kingdom split.</p>",
    "15": "<p>'The LORD will dry up the gulf of the Egyptian Sea and wave his hand over the Euphrates with his scorching wind, breaking it into seven streams so that men can cross it in sandals' — the second Exodus geography: YHWH drying up the 'tongue' of Egypt's sea (leshon yam-Mitsrayim, the gulf/tongue of the Egyptian Sea = the Gulf of Suez, the arm of the Red Sea) as he dried the Red Sea for Moses (Exod 14). Then he breaks the Euphrates (the barrier between Mesopotamia and the promised land) into seven wadis crossable on foot. The new exodus reverses both barriers: the sea that blocked escape from Egypt and the great river that blocked return from Babylon.</p>",
    "16": "<p>'There will be a highway from Assyria for the remnant of his people who survive, just as there was for Israel when they came up out of the land of Egypt' — the highway of return: 'a highway' (mesillah, a raised/built road) from Assyria for the remnant (shear ammo, the remnant of his people), just as there was for Israel in the Exodus. The comparison 'as it was for Israel when they came up from Egypt' (ka'asher haytah leYisrael beyom oloto me'erets Mitsrayim) frames the entire second-Exodus as a typological replay of the first. Isaiah 40:3 ('In the desert prepare the way for the LORD; make straight in the wilderness a highway for our God') and 35:8-10 develop this highway theme, fulfilled in John the Baptist's ministry (Matt 3:3) and the return from Babylon.</p>"
  },
  "12": {
    "1": "<p>'In that day you will say: I praise you, O LORD; though you were angry with me, your anger has turned and you have comforted me' — Isaiah 12 is a brief thanksgiving psalm (6 verses) serving as the doxological conclusion to chs. 7-11: the great Immanuel-messianic section. 'I praise you, though you were angry with me' (odecha YHWH ki anafta bi, I thank you LORD for you were angry with me) — the thanksgiving is grounded in the honesty of having experienced divine anger. The 'though' (ki) is not adversative but causal: precisely because YHWH was angry, the worshiper thanks him — the anger was disciplinary, and the turning of anger (shav appecha, your anger has turned) and the comforting (vatenachameni, and you have comforted me) are the outcome.</p>",
    "2": "<p>'Look — God is my salvation! I will trust and will not be afraid; for the LORD, the LORD himself, is my strength and my song; he has become my deliverance' — the third citation of Exod 15:2 in Isaiah (also 26:1; the first was implicit in 5:13's context): 'YHWH, YHWH himself, is my strength and my song; he has become my salvation' (Yhwh Yhwh uzi vezimrat Yah vayhi li lishuah). The doubled divine name (YHWH, YHWH) and the exact phrase from the Song of the Sea identify this doxology as consciously echoing the Exodus celebration. The eschatological victory over Assyria/Babylon/the nations is narrated in the same vocabulary as the Exodus victory — the new salvation is narrated by the old salvation's language.</p>",
    "3": "<p>'With joy you will draw water from the springs of salvation' — the water-and-salvation image: ushe'avtem mayim besasson mime'ainei hayeshuah (you will draw water with joy from the springs of salvation). The 'springs of salvation' (me'ainei hayeshuah) connect to the gentle Shiloah waters (8:6) rejected in favor of Assyrian alliance, and anticipate 55:1 ('come, all you who are thirsty, come to the waters'). Jesus applies this image in John 4:10-14 (the spring of water welling up to eternal life) and John 7:37-38 ('rivers of living water will flow from within them'). The drawing of water with joy is a harvest-festival image — the Sukkot water-drawing ceremony (beit hashoeva) of the Second Temple period was the setting for John 7.</p>",
    "4": "<p>'In that day you will also say: Give thanks to the LORD; call on his name; make his deeds known among the nations; proclaim that his name is lifted high above all' — the missionary dimension of the eschatological celebration: the personal thanksgiving (vv. 1-2) expands into universal proclamation. 'Make his deeds known among the nations' (hodi'u va'ammim alilotav, make known among the peoples his deeds) — the same mission as Ps 105:1 and 1 Chr 16:8 (David bringing the ark to Jerusalem). The 'name exalted above all' (nishgav shemo, his name is lifted high) becomes the content of the proclamation: YHWH's name, which the Assyrian king thought equal to national deities (10:10-11), is the name exalted above all nations.</p>",
    "5": "<p>'Sing praises to the LORD, for he has done glorious things; make this known throughout all the earth!' — the call to praise (zameru YHWH, sing praises to YHWH) because 'he has done glorious things' (ki ge'ut asah, for he has done majesty/glory). The universal proclamation: 'make this known throughout all the earth!' (muada't zot bechol-ha'arets, let this be known in all the earth). The 'glorious things' are the specific acts of the messianic age described in chs. 9-11 (the great light, the Davidic child, the seven-fold Spirit, the peaceable kingdom, the second exodus). The earth-wide proclamation anticipates the global mission of the NT: 'Go and make disciples of all nations' (Matt 28:19) is grounded in the eschatological proclamation of YHWH's saving acts.</p>",
    "6": "<p>'Cry aloud and shout for joy, you who dwell in Zion, for great is the Holy One of Israel in your midst!' — the closing acclamation: tsahali varonni yoshevet Tsiyon (shout aloud and sing for joy, O inhabitant of Zion). The two verbs of joyful sound (tsahal, ringing cry; ranan, sing/shout) frame the final declaration: 'great is the Holy One of Israel in your midst' (ki gadol beqirbekh qedosh Yisrael). The 'Holy One of Israel' (Isaiah's signature epithet for YHWH, 26 times in Isaiah) is specifically present 'in your midst' (beqirbekh, in your inner parts/among you) — the divine indwelling that Zion was promised and that the messianic age brings to completeness. The short ch. 12 closes the first major Isaianic section (chs. 1-12) on this note of eschatological joy and divine presence.</p>"
  },
  "13": {
    "1": "<p>Isaiah 13 begins the 'Burden' oracles (massa, burden/oracle — the term for a prophetic message heavy with judgment) that run through chs. 13-23: Babylon (13-14), Philistia (14:28-32), Moab (15-16), Damascus (17), Egypt (19), Babylon again (21), Edom (21:11-12), Arabia (21:13-17), Jerusalem (22), Tyre (23). The first and longest concerns Babylon — unusual for an 8th-century prophet since Babylon was not yet the dominant power in Isaiah's time (that came in the 7th-6th century with Nebuchadnezzar). Isaiah's Babylon oracle anticipates the exile that chs. 40-55 address — a prophetic reach forward that the book's canonical structure affirms.</p>",
    "2": "<p>'Raise a banner on the bare mountain! Lift your voice to them! Wave your hand, so that they may march through the gates of the rulers!' — the mustering signal: the banner (nes) raised on the bare mountain (har-nishpeh, a bald/cleared mountain top — a signal fire or flag visible from afar) is YHWH's military deployment command. This is the same signal as 5:26 (YHWH whistling for the distant nation) and 11:10-12 (the banner for the ingathering). Here the signal deploys the divine army against Babylon. 'The gates of the rulers' (she'arei nedivim, the gates of nobles) = the city gates of Babylon's aristocracy — the invading force will enter through Babylon's own gates.</p>",
    "3": "<p>'I have given orders to my consecrated troops; I have summoned my warriors to carry out my wrath — those who exult in my majesty' — YHWH's consecrated/holy troops (meqodeshai, my holy ones = warriors set apart for holy war; cf. Num 31:6; Jer 6:4 where the command to 'consecrate war' = haqdishu milchamah). The divine warrior is calling up his host: both the heavenly armies and the historical Medes who will conquer Babylon (v17). 'Those who exult in my majesty' (alizehai ga'avati, exulting in my pride) — YHWH's warriors who take pride in divine glory, not their own. The consecrated-warrior language contrasts with the Assyrian troops who boasted in their own power (10:13-14).</p>",
    "4": "<p>'Listen — the roar of multitudes on the mountains, like a vast army! The clamour of kingdoms and nations massing together! The LORD of hosts is assembling his battle force' — the auditory vision: qol hamon baharim, demut am-rav (the sound of a multitude on the mountains, the likeness of a great people). The 'multitude on the mountains' is the sound before sight — the army heard at a distance. 'The LORD of hosts is assembling his battle force' (Yhwh tseva'ot mefahed tzeva milchamah) — YHWH mustering his army (milchamah, war/battle forces) is the eschatological war assembly. The combination of 'kingdoms and nations massing together' suggests a force beyond any single national army — the divine coalition exceeds human military categories.</p>",
    "5": "<p>'They are coming from a distant land, from the far end of the heavens — the LORD himself with the instruments of his wrath — to lay waste to the whole earth' — 'from the far end of the heavens' (miqqetseh hashamayim, from the extremity of the heavens) — the divine army's origin point is beyond human geography, from the edge of the cosmos. 'The LORD himself with the instruments of his wrath' (Yhwh ukelei za'amo, YHWH himself and the instruments of his indignation) identifies the army's composition: YHWH commanding human agents who are his weapons. 'The whole earth' (kol-ha'arets) as the target (not just Babylon) signals that the Babylon oracle will expand to universal eschatological judgment, as vv. 9-13 confirm.</p>",
    "6": "<p>'Wail, for the day of the LORD is close at hand — it will come as devastation from the Almighty' — the Day of the LORD (yom Yhwh) announced for Babylon: the same theme as Amos 5:18-20 (woe to those who desire the day of the LORD) and Joel 1-2. 'Devastation from the Almighty' (shod mishaddai, destruction from Shaddai) is a wordplay: shod (devastation) sounds like Shaddai (the Almighty's ancient title). The same wordplay appears in Joel 1:15: 'The day of the LORD is coming. It will come as a destruction from the Almighty.' El-Shaddai (the powerful God of the patriarchs, Gen 17:1; 35:11) becomes the source of shod — the God of ancient covenant blessing becomes the destroyer of his enemies.</p>",
    "7": "<p>'At this every hand will go limp and every human heart will melt with fear' — the universal physical response to the Day of the LORD: 'every hand will go limp' (kol-yadayim tirpeh, all hands become flaccid) and 'every heart will melt' (kol-levav enosh yimmas, every heart of man melts). The melting heart is the terror-response in battle (Deut 20:8; Josh 2:11: Rahab reports that 'our hearts melted in fear' when Israel approached; Josh 5:1: 'all the Amorite and Canaanite kings melted in terror'). These are the same terror-responses that YHWH promised to send against Israel's enemies in holy war — now applied to those experiencing YHWH's own judgment.</p>",
    "8": "<p>'They will be seized with anguish; pangs and agony will grip them; they will writhe like a woman in labour. They will look at one another in horror, their faces burning red' — three word-groups for physical agony: tziruth vecharalot (pangs and convulsions), yacholun kaioledat (they writhe like a woman in labor), ish el-re'ehu yitmehu (each looks at his neighbor in amazement/horror). The woman-in-labor comparison for sudden, unavoidable agony is a recurring prophetic image for military catastrophe (Jer 6:24; 13:21; 22:23; 50:43; Mic 4:9-10). Paul uses the same labor imagery in 1 Thess 5:3: 'destruction will come suddenly, as labor pains on a pregnant woman,' but reverses the application to the unexpected arrival of the Day of the Lord for the unbeliever.</p>",
    "9": "<p>'See, the day of the LORD is coming — relentless in wrath and burning anger — to turn the land into a ruin and wipe out every sinner from it' — the Day of the LORD defined by two attributes: achzar (cruel/relentless) and chemah ve'evron (fury and burning anger). The double-anger vocabulary (chemah = hot anger; evron = overflowing rage/wrath) intensifies the heat-metaphor already in the burning/scorching language. The goal: 'to turn the land into a ruin' (lasim ha'arets leshamamah, to make the land desolate) and 'wipe out every sinner' (vachata'eha yishmid mimmenah, sinners he will destroy from it). The desolation-and-sinner-removal dual purpose marks this as both ecological and moral judgment.</p>",
    "10": "<p>'The stars of heaven and their constellations will not give their light; the sun will be dark when it rises and the moon will not shed its glow' — the cosmic darkening: the celestial lights extinguished. 'Stars' (kochavei hashamayim), 'constellations' (ucsileihem, their Kesils/Orions — kesil is both Orion the constellation and 'fool/obstinate one'), the sun (shemesh) dark at rising, and the moon (yareach) not giving its light. These cosmic signs are the reversal of Gen 1:14-16 (luminaries created to give light). The same imagery recurs in Joel 2:10; 3:15; Matt 24:29; Luke 21:25; Rev 6:12-13 as the signs of the great eschatological Day. The darkening of the luminaries signals the end of the cosmic order sustained since creation.</p>",
    "11": "<p>'I will punish the world for its evil and the wicked for their guilt; I will put an end to the arrogance of the proud and cut down the insolence of tyrants' — the expansion from Babylon-specific to universal judgment: 'the world' (tevel, the habitable earth) is now the scope of YHWH's punishment. The two specific targets: ga'on (arrogance/pride of the proud) and gevah aritsim (haughtiness of tyrants/violent ones) — the same pride-vocabulary as 2:10-22 (the Day-of-the-LORD against everything proud). The Babylon oracle thus becomes a particular instance of the universal Day-of-the-LORD theme that ch. 2 announced: Babylon is the concentrated expression of human pride against which YHWH acts.</p>",
    "12": "<p>'Human life will become rarer than pure gold — rarer even than the gold of Ophir' — the scarcity of survivors: okar enosh miyaqar (I will make a man more precious than refined gold) and adam mizahav Ofir (a man more than the gold of Ophir). Gold of Ophir was the finest gold in the ancient Near East (1 Kgs 9:28: Solomon brought 420 talents of Ophir gold; Ps 45:9: 'fine gold from Ophir'). The rarity metaphor inverts the Day of the LORD's normal population imagery: instead of swarming armies (5:26-30; 13:4), survivors will be as rare as precious metal. The few survivors after judgment are the remnant theology applied to Babylon's judgment.</p>",
    "13": "<p>'I will make the heavens tremble, and the earth will be displaced from its foundations by the wrath of the LORD of hosts on the day of his burning anger' — the cosmic shaking: 'the heavens tremble' (arzil hashamayim, I will shake the heavens) and 'the earth will be displaced from its foundations' (vetirash ha'arets mimqomah, the earth will be shaken from its place). The cosmic foundations of both heaven and earth destabilized by divine anger (beyom charone aph Yhwh, on the day of YHWH's burning nostril-anger). Rev 6:12-17 draws on this for the sixth seal's cosmic earthquake: 'the sky receded like a scroll being rolled up, and every mountain and island was moved from its place.' The theophanic shaking of Ps 18:7 and Hab 3:6 is the background.</p>",
    "14": "<p>'Like a hunted gazelle or like sheep scattered with no one to round them up, each person will flee back to his own people, each run to his own homeland' — the flight: the people of Babylon's empire scatter like a gazelle before a hunter (tsvi, the graceful deer notorious for its speed in flight) or sheep with no shepherd (tso'n ve'ein meqabets, sheep with no one gathering them). Each person flees to their own native population and land — the diaspora communities of the empire dissolving back to ethnic origins. This reflects the actual Cyrus Cylinder policy: Cyrus allowed deported peoples to return to their homelands, including the Jews (Ezra 1:1-4).</p>",
    "15": "<p>'Anyone who is caught will be run through with a sword; anyone taken prisoner will fall by the blade' — the gruesome fate of those who cannot flee: run through (yiddaqer, pierced/stabbed) and fallen by the sword (yippol becherev). The passive verbs acknowledge the overwhelming military force against which there is no resistance. This is the standard ancient Near Eastern description of city conquest: the Assyrian reliefs and annals both document the same treatment of captured soldiers and civilians. For Babylon's fall to Cyrus (539 BCE), the historical record suggests a relatively bloodless conquest, but the oracle's scope is eschatological: the final judgment on all who oppose YHWH.</p>",
    "16": "<p>'Their children will be dashed to pieces in front of them; their homes will be looted and their wives raped' — the most brutal element of ancient siege warfare applied to Babylon: children dashed to pieces (olalehem yirutteshu, their infants will be dashed), houses looted (batteihem yeshosseshu, their homes will be plundered), wives ravished (venesheihem tishakavnah, their wives will lie with men = be raped). These are the standard covenant curses of Deut 28:30 (your wife taken by another man) applied at their most extreme. Ps 137:9 ('blessed is the one who seizes your infants and dashes them against the rocks') voices the same retributive justice against Babylon from the Judean exile's perspective.</p>",
    "17": "<p>'I am rousing the Medes against Babylon — a people who care nothing for silver and feel no pull toward gold' — the specific human instrument: the Medes (Madai, the Indo-European people of northwestern Iran who allied with Babylon to destroy Assyria in 612 BCE at Nineveh, and later participated in Cyrus's Persian victory over Babylon in 539 BCE). The specific characterization 'who care nothing for silver' (lo yachshofu keseph, they do not account silver) suggests a motivation other than plunder — the Medes/Persians under Cyrus were portrayed as liberators (cf. the Cyrus Cylinder), not looters. The historical fulfillment: Cyrus II conquered Babylon in October 539 BCE with little resistance, famously diverting the Euphrates to breach Babylon's defenses.</p>",
    "18": "<p>'Their bows will cut the young men down; they will show no mercy on newborn infants; they will have no pity for children' — the Medes' military ferocity applied universally: bows (qeshet) cutting down young men (yenatelashu ne'arim, they will dash them), no mercy on the fruit of the womb (lo yerachem al-peri beten, they will not show compassion on the fruit of the womb), no pity for children (lo tachov einam al-banim, their eye will not have pity on boys). The triple expression of mercilessness mirrors the triple expression of Babylon's punishment in v16. The instrument of judgment (Medes) is as harsh as the judgment deserves.</p>",
    "19": "<p>'Babylon — the glory of kingdoms, the pride and beauty of the Chaldeans — will be like Sodom and Gomorrah when God overturned them' — the Sodom comparison applied to Babylon: as YHWH 'overturned' (kemahpechat Elohim, like the overthrow of God = divine overthrow) Sodom and Gomorrah, so Babylon. The threefold description of Babylon's glory: 'glory of kingdoms' (tzvi mamlachot, the splendor/gazelle of kingdoms), 'pride of the Chaldeans' (tiferet ge'on Kasdim, the beauty of the pride of the Chaldeans), and 'beauty' (the repetition for emphasis). Ancient Babylon was one of the ancient world's most impressive cities — Herodotus describes its massive walls, the Ishtar Gate, and its hanging gardens. The comparison to Sodom promises complete annihilation.</p>",
    "20": "<p>'It will never be lived in or settled again through all generations; no Bedouin will pitch a tent there, no shepherds will let their flocks rest there' — the permanent desolation oracle: lo-teshev lanetsach velo tishkon (it will never be inhabited and never be dwelt in) through all generations (ledor vador, from generation to generation). The two specific witnesses to permanence: no Bedouin tent (ohel lo-ya'al sham aravi, the Arab/nomad will not pitch his tent there) and no shepherd resting flocks (ro'im lo yarbitsun sham, shepherds will not let their flocks lie down there). In the ancient world, abandoned ruins typically served as campgrounds for nomads — if not even Bedouins will camp there, the desolation is complete.</p>",
    "21": "<p>'Desert creatures will take up residence there; their empty houses will be full of owls; ostriches will make their home there and wild goats will frolic there' — the ecological catalogue of desolation: tsiyyim (desert creatures/hyenas), ochim (owls), yene'im (ostriches), se'irim (wild goats/demons — se'ir can mean hairy ones, goats, or the goat-demons of Lev 17:7 and 2 Chr 11:15). The animals that inhabit ruins rather than cultivated land are the index of complete abandonment. This is the reverse of Ps 104's ecological catalogue of fruitful creation — the peaceable kingdom of ch. 11 inverted into the chaotic wilderness of Babylon's ruins. Revelation 18:2 applies similar language to the eschatological Babylon: 'Fallen! Fallen is Babylon the Great! She has become a dwelling for demons and a haunt for every impure spirit.'</p>",
    "22": "<p>'Hyenas will cry out in her citadels and jackals in her splendid palaces. Her time is about to come; her days will not be drawn out' — the completion of the desolation catalogue: iyim (howling jackals/hyenas) in her citadels (be'armenoteiha, in her fortified palaces/citadels) and tannim (jackals/dragons) in the 'temples of pleasure' (beheichalei oneg, in the pleasure-palaces). The contrast between the original purpose (citadels of power, pleasure-palaces of the rich) and the actual inhabitants (wild animals) completes the reversal of Babylonian pride. 'Her time is about to come' (ve'arob ittah, her time is near) and 'her days will not be drawn out' (uyameha lo ye'arechun, her days will not be prolonged) — the closing urgency note: Babylon's end is certain and imminent.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
